#include<bits/stdc++.h>
using namespace std;
int ap[2010],bp[2010],as[2010],bs[2010];
int f[2010][2010];
int main()
{
    memset(f,0x80,sizeof(f));
    int n,m,w;
    scanf("%d%d%d",&n,&m,&w);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d%d",&ap[i],&bp[i],&as[i],&bs[i]);
    }
    f[0][0]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<=m;j++)
        {
            f[i][j]=f[i-1][j];
            if(j<=as[i])
            {
                f[i][j]=max(f[i][j],-j*ap[i]);
            }
        }
        if(i<=w)
        {
            continue;
        }
        deque<int> q;
        for(int j=0;j<=m;j++)
        {
            while(!q.empty()&&q.front()<j-as[i])
            {
                q.pop_front();
            }
            int val=f[i-w-1][j]+j*ap[i];
            while(!q.empty()&&f[i-w-1][q.back()]+q.back()*ap[i]<=val)
            {
                q.pop_back();
            }
            q.push_back(j);
            if(!q.empty())
            {
                f[i][j]=max(f[i][j],f[i-w-1][q.front()]+q.front()*ap[i]-j*ap[i]);
            }
        }
        q.clear();
        for(int j=m;j>=0;j--)
        {
            while(!q.empty()&&q.front()>j+bs[i])
            {
                q.pop_front();
            }
            int val=f[i-w-1][j]+j*bp[i];
            while(!q.empty()&&f[i-w-1][q.back()]+q.back()*bp[i]<=val)
            {
                q.pop_back();
            }
            q.push_back(j);
            if(!q.empty())
            {
                f[i][j]=max(f[i][j],f[i-w-1][q.front()]+q.front()*bp[i]-j*bp[i]);
            }
        }
    }
    int ans=0;
    for(int i=0;i<=m;i++)
    {
        ans=max(ans,f[n][i]);
    }
    printf("%d",ans);
    return 0;
}
